import { supabase } from '../lib/supabase'
import type {
  TrainingExecution,
  TrainingExecutionInsert,
  TrainingExecutionUpdate,
  TrainingExecutionWithPlan,
} from '../types/database'

export async function getTrainingExecutions(userId?: string): Promise<TrainingExecutionWithPlan[]> {
  let query = supabase
    .from('training_executions')
    .select('*, training_plans(*)')
    .order('created_at', { ascending: false })

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error
  return data ?? []
}

export async function getTrainingExecution(id: number, userId?: string): Promise<TrainingExecution | null> {
  let query = supabase
    .from('training_executions')
    .select('*')
    .eq('id', id)

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query.single()

  if (error) throw error
  return data
}

export async function getTrainingExecutionsByPlanId(
  planId: number,
  userId?: string
): Promise<TrainingExecution[]> {
  let query = supabase
    .from('training_executions')
    .select('*')
    .eq('plan_id', planId)
    .order('created_at', { ascending: false })

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error
  return data ?? []
}

export async function getTrainingExecutionsByDateRange(
  startDate: string,
  endDate: string,
  userId?: string
): Promise<TrainingExecutionWithPlan[]> {
  let query = supabase
    .from('training_executions')
    .select('*, training_plans(*)')
    .gte('completed_at', startDate)
    .lte('completed_at', endDate)
    .order('completed_at', { ascending: true })

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error
  return data ?? []
}

export async function createTrainingExecution(
  execution: TrainingExecutionInsert
): Promise<TrainingExecution> {
  const { data, error } = await supabase
    .from('training_executions')
    .insert(execution)
    .select()
    .single()

  if (error) throw error
  return data
}

export async function deleteTrainingExecution(id: number): Promise<void> {
  const { error } = await supabase.from('training_executions').delete().eq('id', id)

  if (error) throw error
}

export async function updateTrainingExecution(
  id: number,
  execution: TrainingExecutionUpdate
): Promise<TrainingExecution> {
  const { data, error } = await supabase
    .from('training_executions')
    .update(execution)
    .eq('id', id)
    .select()
    .single()

  if (error) throw error
  return data
}

export async function getCompletedUnitsByPlanIds(
  planIds: number[],
  userId?: string
): Promise<Map<number, number>> {
  if (planIds.length === 0) return new Map()

  let query = supabase
    .from('training_executions')
    .select('plan_id, unit_count')
    .in('plan_id', planIds)

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error

  const map = new Map<number, number>()
  for (const row of data ?? []) {
    map.set(row.plan_id, (map.get(row.plan_id) ?? 0) + row.unit_count)
  }
  return map
}

export async function getTodaysExecutionsByPlanIds(
  planIds: number[],
  userId?: string
): Promise<TrainingExecution[]> {
  if (planIds.length === 0) return []

  const today = new Date()
  const startOfDay = new Date(today.getFullYear(), today.getMonth(), today.getDate()).toISOString()
  const endOfDay = new Date(
    today.getFullYear(),
    today.getMonth(),
    today.getDate(),
    23,
    59,
    59,
    999
  ).toISOString()

  let query = supabase
    .from('training_executions')
    .select('*')
    .in('plan_id', planIds)
    .gte('completed_at', startOfDay)
    .lte('completed_at', endOfDay)

  if (userId) {
    query = query.eq('user_id', userId)
  }

  const { data, error } = await query

  if (error) throw error
  return data ?? []
}

// 통계 계산 함수들
export function calculateStats(executions: TrainingExecution[]) {
  if (executions.length === 0) {
    return {
      totalSessions: 0,
      totalUnits: 0,
      totalDuration: 0,
      avgDuration: 0,
      avgDurationPerUnit: 0,
    }
  }

  const totalSessions = executions.length
  const totalUnits = executions.reduce((sum, e) => sum + e.unit_count, 0)
  const totalDuration = executions.reduce((sum, e) => sum + e.duration_seconds, 0)
  const avgDuration = totalDuration / totalSessions
  const avgDurationPerUnit = totalUnits > 0 ? totalDuration / totalUnits : 0

  return {
    totalSessions,
    totalUnits,
    totalDuration,
    avgDuration,
    avgDurationPerUnit,
  }
}
